5	interface AssetListViewProps {
6	  assets: Asset[];
7	  selectedIds: Set<string>;
8	  onSelect: (id: string, event: React.MouseEvent) => void;
9	  isLoading: boolean;
10	}
11	
12	// Colors keyed by file_type enum value
13	const FILE_TYPE_META: Record<string, { label: string; bg: string; color: string }> = {
14	  psd: { label: "PSD", bg: "#7c3aed", color: "#fff" },
15	  ai:  { label: "AI",  bg: "#ea580c", color: "#fff" },
16	  png: { label: "PNG", bg: "#0d9488", color: "#fff" },
17	  pdf: { label: "PDF", bg: "#dc2626", color: "#fff" },
18	  jpg: { label: "JPG", bg: "#2563eb", color: "#fff" },
19	  tif: { label: "TIF", bg: "#7c3aed", color: "#fff" }, // violet (same hue as PSD)
20	};
21	
22	function FileTypeBadge({ fileType }: { fileType: string }) {
23	  const meta = FILE_TYPE_META[fileType?.toLowerCase()] ?? {
24	    label: (fileType ?? "?").toUpperCase(),
25	    bg: "#64748b",
26	    color: "#fff",
27	  };
28	  return (
29	    <div
30	      style={{
31	        width: 36,
32	        height: 28,
33	        borderRadius: 6,
34	        background: meta.bg,
35	        color: meta.color,
36	        display: "flex",
37	        alignItems: "center",
38	        justifyContent: "center",
39	        fontSize: 10,
40	        fontWeight: 700,
41	        letterSpacing: "0.04em",
42	        flexShrink: 0,
43	        fontFamily: "var(--font-mono, monospace)",
44	      }}
45	    >
46	      {meta.label}
47	    </div>
48	  );
