50	
51	function formatSize(bytes: number | null | undefined): string {
52	  if (!bytes) return "—";
53	  if (bytes < 1024) return `${bytes} B`;
54	  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
55	  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
56	  return `${(bytes / (1024 * 1024 * 1024)).toFixed(2)} GB`;
57	}
58	
59	function relativeTime(dateStr: string): string {
60	  const diff = Date.now() - new Date(dateStr).getTime();
61	  const mins = Math.floor(diff / 60_000);
62	  if (mins < 1) return "just now";
63	  if (mins < 60) return `${mins}m ago`;
64	  const hrs = Math.floor(mins / 60);
65	  if (hrs < 24) return `${hrs}h ago`;
66	  const days = Math.floor(hrs / 24);
67	  if (days < 30) return `${days}d ago`;
68	  const months = Math.floor(days / 30);
69	  if (months < 12) return `${months}mo ago`;
70	  return `${Math.floor(months / 12)}y ago`;
71	}
72	
73	function isSuperseded(asset: Asset): boolean {
74	  return asset.workflow_status === "discontinued";
75	}
76	
77	export default function AssetListView({ assets, selectedIds, onSelect, isLoading }: AssetListViewProps) {
78	  if (isLoading && assets.length === 0) {
79	    return (
80	      <div className="p-4 space-y-2">
81	        {Array.from({ length: 8 }).map((_, i) => (
82	          <div key={i} className="h-12 rounded bg-muted/30 animate-pulse" />
83	        ))}
84	      </div>
85	    );
86	  }
87	
88	  if (assets.length === 0) {
89	    return (
90	      <div className="flex flex-col items-center justify-center py-24 text-center">
91	        <ImageOff className="h-12 w-12 text-muted-foreground/30 mb-4" />
92	        <p className="text-muted-foreground">No assets found</p>
93	      </div>
94	    );
95	  }
96	
97	  return (
98	    <div className="w-full">
99	      {/* Header */}
100	      <div
101	        className="grid items-center border-b border-border px-3 py-1.5"
102	        style={{ gridTemplateColumns: "40px 1.8fr 1.2fr .7fr .7fr" }}
103	      >
104	        <div />
105	        <div className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide">Filename</div>
106	        <div className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide">Style group</div>
107	        <div className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide">Size</div>
108	        <div className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide text-right">Modified</div>
109	      </div>
110	
111	      {/* Rows */}
112	      <div>
113	        {assets.map((asset) => {
114	          const selected = selectedIds.has(asset.id);
115	          const superseded = isSuperseded(asset);
116	          const skuLine = asset.sku ?? null;
117	          const subtitleParts = [asset.property_name, asset.licensor_name].filter(Boolean);
118	          const subtitle = subtitleParts.length > 0 ? subtitleParts.join(" · ") : null;
119	
120	          return (
121	            <div
122	              key={asset.id}
123	              onClick={(e) => onSelect(asset.id, e)}
124	              className={cn(
125	                "grid items-center px-3 cursor-pointer border-b border-border/50 transition-colors",
126	                "hover:bg-muted/40",
127	                selected && "bg-primary/10 hover:bg-primary/15"
128	              )}
129	              style={{ gridTemplateColumns: "40px 1.8fr 1.2fr .7fr .7fr", minHeight: 48 }}
130	            >
131	              {/* Type badge */}
132	              <div className="flex items-center">
133	                <FileTypeBadge fileType={asset.file_type} />
134	              </div>
135	
136	              {/* Filename */}
137	              <div className="min-w-0 pr-3">
138	                <div
139	                  className="truncate font-mono text-[12.5px] font-semibold leading-tight"
140	                  title={asset.filename}
141	                >
142	                  {asset.filename}
143	                </div>
144	                <div
145	                  className="text-[11px] leading-tight mt-0.5"
146	                  style={{ color: "var(--pd-fg-subtle)" }}
147	                >
148	                  {superseded ? "superseded" : "current version"}
149	                </div>
150	              </div>
151	
152	              {/* Style group */}
153	              <div className="min-w-0 pr-3">
154	                {skuLine && (
155	                  <div
156	                    className="truncate font-mono text-[11.5px] font-medium leading-tight"
157	                    title={skuLine}
158	                  >
159	                    {skuLine}
160	                  </div>
161	                )}
162	                {subtitle && (
163	                  <div
164	                    className="truncate text-[11px] leading-tight mt-0.5"
165	                    style={{ color: "var(--pd-fg-muted)" }}
166	                    title={subtitle}
167	                  >
168	                    {subtitle}
169	                  </div>
170	                )}
171	                {!skuLine && !subtitle && (
172	                  <span className="text-[11.5px] font-mono" style={{ color: "var(--pd-fg-muted)" }}>—</span>
173	                )}
174	              </div>
175	
176	              {/* Size */}
177	              <div
178	                className="font-mono text-[12px] tabular-nums"
179	                style={{ color: "var(--pd-fg-muted)" }}
180	              >
181	                {formatSize(asset.file_size)}
182	              </div>
183	
184	              {/* Modified */}
185	              <div
186	                className="text-[12px] tabular-nums text-right"
187	                style={{ color: "var(--pd-fg-muted)" }}
188	                title={new Date(asset.modified_at).toLocaleString()}
189	              >
190	                {relativeTime(asset.modified_at)}
191	              </div>
192	            </div>
193	          );
194	        })}
195	      </div>
196	    </div>
197	  );
198	}
