165	interface AssetDetailPanelProps {
166	  asset: Asset;
167	  onClose: () => void;
168	  onOpenGroup?: (groupId: string) => void;
169	}
170	
171	export default function AssetDetailPanel({ asset, onClose, onOpenGroup }: AssetDetailPanelProps) {
172	  const queryClient = useQueryClient();
173	  const [editingTags, setEditingTags] = useState(false);
174	  const [tagInput, setTagInput] = useState("");
175	  const [aiTagging, setAiTagging] = useState(false);
176	  const [pathMode, setPathModeState] = useState<PathMode>(getPreferredPathMode);
177	  const [syncRoot, setSyncRootState] = useState<string>(getUserSyncRoot() ?? "");
178	  const [copyingPath, setCopyingPath] = useState(false);
179	
180	  const fileType = (asset.file_type ?? "").toLowerCase();
181	  const typeColor = getTypeColor(fileType);
182	  const typeHue = getTypeHue(fileType);
183	
184	  // ── NAS config ──────────────────────────────────────────────
185	  const { data: nasConfig } = useQuery({
186	    queryKey: ["nas-config"],
187	    queryFn: async () => {
188	      const { data, error } = await supabase
189	        .from("admin_config")
190	        .select("key, value")
191	        .in("key", ["NAS_HOST", "NAS_IP", "NAS_SHARE"]);
192	      if (error) throw error;
193	      const map: Record<string, string> = {};
194	      for (const row of data ?? []) {
195	        map[row.key] = typeof row.value === "string" ? row.value : String(row.value);
196	      }
197	      return {
198	        NAS_HOST: map.NAS_HOST ?? "nas",
199	        NAS_IP: map.NAS_IP ?? "0.0.0.0",
200	        NAS_SHARE: map.NAS_SHARE ?? "share",
201	      } as NasConfig;
202	    },
203	    staleTime: 5 * 60 * 1000,
204	  });
205	
206	  // ── Path history ─────────────────────────────────────────────
207	  const { data: pathHistory } = useQuery({
208	    queryKey: ["path-history", asset.id],
209	    queryFn: async () => {
210	      const { data, error } = await supabase
211	        .from("asset_path_history")
212	        .select("*")
213	        .eq("asset_id", asset.id)
214	        .order("detected_at", { ascending: false })
215	        .limit(10);
216	      if (error) throw error;
217	      return data ?? [];
218	    },
219	  });
220	
221	  // ── Licensor / property names ─────────────────────────────────
222	  const { data: licensorName } = useQuery({
223	    queryKey: ["licensor-name", asset.licensor_id],
224	    queryFn: async () => {
225	      if (!asset.licensor_id) return null;
226	      const { data } = await supabase.from("licensors").select("name").eq("id", asset.licensor_id).single();
227	      return data?.name ?? null;
228	    },
229	    enabled: !!asset.licensor_id,
230	  });
231	
232	  const { data: propertyName } = useQuery({
233	    queryKey: ["property-name", asset.property_id],
234	    queryFn: async () => {
235	      if (!asset.property_id) return null;
236	      const { data } = await supabase.from("properties").select("name").eq("id", asset.property_id).single();
237	      return data?.name ?? null;
238	    },
239	    enabled: !!asset.property_id,
240	  });
241	
242	  // ── Style group data (for "Belongs to" card) ─────────────────
243	  const styleGroupId = (asset as any).style_group_id as string | null | undefined;
244	  const { data: styleGroup } = useQuery({
245	    queryKey: ["style-group-brief", styleGroupId],
246	    queryFn: async () => {
247	      if (!styleGroupId) return null;
248	      const { data } = await supabase
249	        .from("style_groups")
250	        .select("id, sku, licensor_id, property_id")
251	        .eq("id", styleGroupId)
252	        .single();
253	      return data ?? null;
254	    },
255	    enabled: !!styleGroupId,
256	  });
257	
258	  const { data: sgLicensorName } = useQuery({
259	    queryKey: ["licensor-name", styleGroup?.licensor_id],
260	    queryFn: async () => {
261	      if (!styleGroup?.licensor_id) return null;
262	      const { data } = await supabase.from("licensors").select("name").eq("id", styleGroup.licensor_id).single();
263	      return data?.name ?? null;
264	    },
265	    enabled: !!styleGroup?.licensor_id,
266	  });
267	
268	  const { data: sgPropertyName } = useQuery({
269	    queryKey: ["property-name", styleGroup?.property_id],
270	    queryFn: async () => {
271	      if (!styleGroup?.property_id) return null;
272	      const { data } = await supabase.from("properties").select("name").eq("id", styleGroup.property_id).single();
273	      return data?.name ?? null;
274	    },
275	    enabled: !!styleGroup?.property_id,
276	  });
277	
278	  // ── Update mutation ───────────────────────────────────────────
279	  const updateAsset = useMutation({
280	    mutationFn: async (updates: Record<string, unknown>) => {
281	      const { data, error } = await supabase.from("assets").update(updates).eq("id", asset.id).select("id");
282	      if (error) throw error;
283	      if (!data || data.length === 0) throw new Error("Update was blocked — you may not have permission to edit this asset");
284	    },
285	    onSuccess: () => {
286	      queryClient.invalidateQueries({ queryKey: ["assets"] });
287	      toast("Asset updated");
288	    },
289	    onError: (e) => {
290	      toast.error("Update failed", { description: e.message });
291	    },
292	  });
293	
294	  // ── AI tag ────────────────────────────────────────────────────
295	  const handleAiTag = async () => {
296	    setAiTagging(true);
297	    try {
298	      const opKey = `ai-tag-single-${asset.id}`;
299	      const now = new Date().toISOString();
300	      const { error } = await supabase.rpc("update_bulk_operation", {
301	        p_op_key: opKey,
302	        p_op_state: {
303	          status: "running",
304	          cursor: 0,
305	          params: { type: "bulk-ai-tag-all", asset_ids: [asset.id], total: 1 },
306	          started_at: now,
307	          updated_at: now,
308	          progress: { tagged: 0, skipped: 0, failed: 0, total: 1 },
309	        },
310	      });
311	      if (error) throw error;
312	
313	      const maxWaitMs = 90_000;
314	      const pollMs = 2_000;
315	      const start = Date.now();
316	      while (Date.now() - start < maxWaitMs) {
317	        await new Promise((r) => setTimeout(r, pollMs));
318	        const { data: configRow } = await supabase
319	          .from("admin_config")
320	          .select("value")
321	          .eq("key", "BULK_OPERATIONS")
322	          .maybeSingle();
323	        const ops = configRow?.value as Record<string, any> | undefined;
324	        const op = ops?.[opKey];
325	        if (!op || op.status === "completed") {
326	          try {
327	            await supabase.rpc("update_bulk_operation", {
328	              p_op_key: opKey,
329	              p_op_state: { status: "idle" },
330	            });
331	          } catch { /* best-effort cleanup */ }
332	          queryClient.invalidateQueries({ queryKey: ["assets"] });
333	          queryClient.invalidateQueries({ queryKey: ["asset-tags", asset.id] });
334	          toast("AI tagging complete");
335	          return;
336	        }
337	        if (op.status === "failed" || op.status === "interrupted") {
338	          throw new Error(op.error || "AI tagging failed");
339	        }
340	      }
341	      toast("AI tagging is still running — check back shortly");
342	    } catch (e: any) {
343	      toast.error("AI tagging failed", { description: e.message });
344	    } finally {
345	      setAiTagging(false);
346	    }
347	  };
348	
349	  // ── Tag provenance ────────────────────────────────────────────
350	  const { data: assetTags } = useQuery({
351	    queryKey: ["asset-tags", asset.id],
352	    queryFn: async () => {
353	      const { data, error } = await supabase
354	        .from("asset_tags")
355	        .select("id, tag, source, created_by")
356	        .eq("asset_id", asset.id)
357	        .order("tag");
358	      if (error) throw error;
359	      return data ?? [];
360	    },
361	  });
362	
363	  const tagSourceMap = new Map<string, string>();
364	  for (const t of assetTags ?? []) {
365	    tagSourceMap.set(t.tag, t.source);
366	  }
367	
368	  // ── Tag CRUD ──────────────────────────────────────────────────
369	  const addTag = async () => {
370	    const tag = tagInput.trim().toLowerCase();
371	    if (!tag || asset.tags.includes(tag)) return;
372	    const { data, error } = await supabase.from("asset_tags").upsert(
373	      { asset_id: asset.id, tag, source: "manual" },
374	      { onConflict: "asset_id,tag" }
375	    ).select("id");
376	    if (error) { toast.error("Failed to add tag", { description: error.message }); return; }
